89: 	Notifications.onNewNotification = function (notifData) {
90: 		if (ajaxify.currentPage === 'notifications') {
91: 			ajaxify.refresh();
92: 		}
93: 		if (ajaxify.data.template.chats && parseInt(ajaxify.data.roomId, 10) === parseInt(notifData.roomId, 10)) {
94: 			return;
95: 		}
96: 
97: 		socket.emit('notifications.getCount', function (err, count) {
98: 			if (err) {
99: 				return alerts.error(err);
100: 			}
101: 
102: 			Notifications.updateNotifCount(count);
103: 		});
104: 
105: 		if (!unreadNotifs[notifData.nid]) {
106: 			unreadNotifs[notifData.nid] = true;
107: 		}
108: 	};
109: 
110: 	Notifications.markNotification = function (nid, read, callback) {
111: 		markNotification(nid, read, callback);
112: 	};
113: 
114: 	function markNotification(nid, read, callback) {
115: 		socket.emit('notifications.mark' + (read ? 'Read' : 'Unread'), nid, function (err) {
116: 			if (err) {
117: 				return alerts.error(err);
118: 			}
119: 
120: 			if (read && unreadNotifs[nid]) {
121: 				delete unreadNotifs[nid];
122: 			}
123: 			if (callback) {
124: 				callback();
125: 			}
126: 		});
127: 	}
