225: 	function topicCommand(method, path, command, onComplete) {
226: 		if (!onComplete) {
227: 			onComplete = function () {};
228: 		}
229: 		const tid = ajaxify.data.tid;
230: 		const body = {};
231: 		const execute = function (ok) {
232: 			if (ok) {
233: 				api[method](`/topics/${tid}${path}`, body)
234: 					.then(onComplete)
235: 					.catch(alerts.error);
236: 			}
237: 		};
238: 
239: 		switch (command) {
240: 			case 'delete':
241: 			case 'restore':
242: 			case 'purge':
243: 				bootbox.confirm(`[[topic:thread-tools.${command}-confirm]]`, execute);
244: 				break;
245: 
246: 			case 'pin':
247: 				ThreadTools.requestPinExpiry(body, execute.bind(null, true));
248: 				break;
249: 
250: 			default:
251: 				execute(true);
252: 				break;
253: 		}
254: 	}
