256: 	ThreadTools.requestPinExpiry = function (body, onSuccess) {
257: 		app.parseAndTranslate('modals/set-pin-expiry', {}, function (html) {
258: 			const modal = bootbox.dialog({
259: 				title: '[[topic:thread-tools.pin]]',
260: 				message: html,
261: 				onEscape: true,
262: 				buttons: {
263: 					cancel: {
264: 						label: '[[modules:bootbox.cancel]]',
265: 						className: 'btn-link',
266: 					},
267: 					save: {
268: 						label: '[[global:save]]',
269: 						className: 'btn-primary',
270: 						callback: function () {
271: 							const expiryDateEl = modal.get(0).querySelector('#expiry-date');
272: 							const expiryTimeEl = modal.get(0).querySelector('#expiry-time');
273: 							let expiryDate = expiryDateEl.value;
274: 							let expiryTime = expiryTimeEl.value;
275: 							// No expiry set
276: 							if (expiryDate === '' && expiryTime === '') {
277: 								return onSuccess();
278: 							}
279: 							expiryDate = expiryDate || new Date().toDateString();
280: 							expiryTime = expiryTime || new Date().toTimeString();
281: 							const date = new Date(`${expiryDate} ${expiryTime}`);
282: 							if (date.getTime() > Date.now()) {
283: 								body.expiry = date.getTime();
284: 								onSuccess();
285: 							} else {
286: 								alerts.error('[[error:invalid-date]]');
287: 							}
288: 						},
289: 					},
290: 				},
291: 			});
292: 		});
