4: define('forum/topic/move', [
5: 	'categorySelector', 'alerts', 'hooks',
6: ], function (categorySelector, alerts, hooks) {
7: 	const Move = {};
8: 	let modal;
9: 	let selectedCategory;
10: 
11: 	Move.init = function (tids, currentCid, onComplete) {
12: 		if (modal) {
13: 			return;
14: 		}
15: 		Move.tids = tids;
16: 		Move.currentCid = currentCid;
17: 		Move.onComplete = onComplete;
18: 		Move.moveAll = !tids;
19: 
20: 		showModal();
21: 	};
22: 
23: 	function showModal() {
24: 		app.parseAndTranslate('modals/move-topic', {}, function (html) {
25: 			modal = html;
26: 			$('body').append(modal);
27: 
28: 			if (Move.moveAll || (Move.tids && Move.tids.length > 1)) {
29: 				modal.find('.card-header').translateText('[[topic:move-topics]]');
30: 			}
31: 
32: 			categorySelector.init(modal.find('[component="category-selector"]'), {
33: 				onSelect: onCategorySelected,
34: 				privilege: 'moderate',
35: 			});
36: 
37: 			modal.find('#move_thread_commit').on('click', onCommitClicked);
38: 			modal.find('#move_topic_cancel').on('click', closeMoveModal);
39: 		});
40: 	}
41: 
42: 	function onCategorySelected(category) {
43: 		selectedCategory = category;
44: 		modal.find('#move_thread_commit').prop('disabled', false);
45: 	}
46: 
47: 	function onCommitClicked() {
48: 		const commitEl = modal.find('#move_thread_commit');
49: 
50: 		if (!commitEl.prop('disabled') && selectedCategory && selectedCategory.cid) {
51: 			commitEl.prop('disabled', true);
52: 			closeMoveModal();
53: 			let message = '[[topic:topic-move-success, ' + selectedCategory.name + ']]';
54: 			if (Move.tids && Move.tids.length > 1) {
55: 				message = '[[topic:topic-move-multiple-success, ' + selectedCategory.name + ']]';
56: 			} else if (!Move.tids) {
57: 				message = '[[topic:topic-move-all-success, ' + selectedCategory.name + ']]';
58: 			}
59: 			const data = {
60: 				tids: Move.tids ? Move.tids.slice() : null,
61: 				cid: selectedCategory.cid,
62: 				currentCid: Move.currentCid,
63: 				onComplete: Move.onComplete,
64: 			};
65: 			if (config.undoTimeout > 0) {
66: 				return alerts.alert({
67: 					alert_id: 'tids_move_' + (Move.tids ? Move.tids.join('-') : 'all'),
68: 					title: '[[topic:thread-tools.move]]',
69: 					message: message,
70: 					type: 'success',
71: 					timeout: config.undoTimeout,
72: 					timeoutfn: function () {
73: 						moveTopics(data);
74: 					},
75: 					clickfn: function (alert, params) {
76: 						delete params.timeoutfn;
77: 						alerts.success('[[topic:topic-move-undone]]');
78: 					},
79: 				});
80: 			}
81: 
82: 			moveTopics(data);
83: 		}
84: 	}
85: 
86: 	function moveTopics(data) {
87: 		hooks.fire('action:topic.move', data);
88: 
89: 		socket.emit(!data.tids ? 'topics.moveAll' : 'topics.move', data, function (err) {
90: 			if (err) {
91: 				return alerts.error(err);
92: 			}
93: 
94: 			if (typeof data.onComplete === 'function') {
95: 				data.onComplete();
96: 			}
97: 		});
98: 	}
99: 
100: 	function closeMoveModal() {
101: 		if (modal) {
102: 			modal.remove();
103: 			modal = null;
104: 		}
105: 	}
106: 
107: 	return Move;
108: });
