   193→			if (checkDuration(postEditDuration, timestamp, 'post-edit-duration-expired')) {
   194→				hooks.fire('action:composer.post.edit', {
   195→					pid: getData(btn, 'data-pid'),
   196→				});
   197→			}
   198→		});
   199→
   200→		if (config.enablePostHistory && ajaxify.data.privileges['posts:history']) {
   201→			postContainer.on('click', '[component="post/view-history"], [component="post/edit-indicator"]', function () {
   202→				const btn = $(this);
