   218→		function checkDuration(duration, postTimestamp, languageKey) {
   219→			if (!ajaxify.data.privileges.isAdminOrMod && duration && Date.now() - postTimestamp > duration * 1000) {
   220→				const numDays = Math.floor(duration / 86400);
   221→				const numHours = Math.floor((duration % 86400) / 3600);
   222→				const numMinutes = Math.floor(((duration % 86400) % 3600) / 60);
   223→				const numSeconds = ((duration % 86400) % 3600) % 60;
   224→				let msg = '[[error:' + languageKey + ', ' + duration + ']]';
   225→				if (numDays) {
   226→					if (numHours) {
   227→						msg = '[[error:' + languageKey + '-days-hours, ' + numDays + ', ' + numHours + ']]';
   228→					} else {
   229→						msg = '[[error:' + languageKey + '-days, ' + numDays + ']]';
   230→					}
   231→				} else if (numHours) {
   232→					if (numMinutes) {
   233→						msg = '[[error:' + languageKey + '-hours-minutes, ' + numHours + ', ' + numMinutes + ']]';
   234→					} else {
   235→						msg = '[[error:' + languageKey + '-hours, ' + numHours + ']]';
   236→					}
   237→				} else if (numMinutes) {
   238→					if (numSeconds) {
   239→						msg = '[[error:' + languageKey + '-minutes-seconds, ' + numMinutes + ', ' + numSeconds + ']]';
   240→					} else {
   241→						msg = '[[error:' + languageKey + '-minutes, ' + numMinutes + ']]';
   242→					}
   243→				}
   244→				alerts.error(msg);
   245→				return false;
   246→			}
   247→			return true;
   248→		}
