   444→
   445→			const route = action === 'purge' ? '' : '/state';
   446→			const method = action === 'restore' ? 'put' : 'del';
   447→			api[method](`/posts/${encodeURIComponent(pid)}${route}`).catch(alerts.error);
   448→		});
