   536→
   537→		const selection = window.getSelection();
   538→		if (selection.focusNode && selection.type === 'Range' && ajaxify.data.template.topic) {
   539→			const focusNode = $(selection.focusNode);
   540→			const anchorNode = $(selection.anchorNode);
   541→			const firstPid = anchorNode.parents('[data-pid]').attr('data-pid');
   542→			const lastPid = focusNode.parents('[data-pid]').attr('data-pid');
   543→			if (firstPid !== lastPid || !focusNode.parents('[component="post/content"]').length || !anchorNode.parents('[component="post/content"]').length) {
