					type: 'post',
					id: pid,
				});
			});
		});

		postContainer.on('click', '[component="post/already-flagged"]', function () {
			const flagId = $(this).data('flag-id');
			require(['flags'], function (flags) {
				bootbox.confirm('[[flags:modal-confirm-rescind]]', function (confirm) {
